async function handleCreateUser(req: Request): Promise<Response> {
  const user: User = await req.json();
  user.createdAt = Date.now();

  await kv.set(["users", user.id], user);
  await kv.set(["users", "by_email", user.email], user.id);
  await kv.set(["users", "by_city", user.city, user.id], user.id);
  await kv.set(["users", "by_country", user.country, user.id], user.id);
  await kv.set(["users", "by_role", user.role, user.id], user.id);
  await kv.set(["users", "by_status", user.status, user.id], user.id);

  return new Response(JSON.stringify(user), {
    status: 201,
    headers: { "Content-Type": "application/json" },
  });
}

async function handleCreateProduct(req: Request): Promise<Response> {
  const product: Product = await req.json();
  product.createdAt = Date.now();

  await kv.set(["products", product.id], product);
  await kv.set(["products", "by_category", product.category, product.id], product.id);
  await kv.set(["products", "by_brand", product.brand, product.id], product.id);

  for (const tag of product.tags) {
    await kv.set(["products", "by_tag", tag, product.id], product.id);
  }

  return new Response(JSON.stringify(product), {
    status: 201,
    headers: { "Content-Type": "application/json" },
  });
}

