async function handleUpdateUser(userId: string, req: Request): Promise<Response> {
  const existingResult = await kv.get<User>(["users", userId]);

  if (!existingResult.value) {
    return new Response(JSON.stringify({ error: "User not found" }), {
      status: 404,
      headers: { "Content-Type": "application/json" },
    });
  }

  const updates = await req.json();
  const oldUser = existingResult.value;
  const updatedUser = { ...oldUser, ...updates, id: userId };

  await kv.set(["users", userId], updatedUser);

  if (updates.email && updates.email !== oldUser.email) {
    await kv.delete(["users", "by_email", oldUser.email]);
    await kv.set(["users", "by_email", updatedUser.email], userId);
  }

  if (updates.city && updates.city !== oldUser.city) {
    await kv.delete(["users", "by_city", oldUser.city, userId]);
    await kv.set(["users", "by_city", updatedUser.city, userId], userId);
  }

  if (updates.country && updates.country !== oldUser.country) {
    await kv.delete(["users", "by_country", oldUser.country, userId]);
    await kv.set(["users", "by_country", updatedUser.country, userId], userId);
  }

  if (updates.role && updates.role !== oldUser.role) {
    await kv.delete(["users", "by_role", oldUser.role, userId]);
    await kv.set(["users", "by_role", updatedUser.role, userId], userId);
  }

  if (updates.status && updates.status !== oldUser.status) {
    await kv.delete(["users", "by_status", oldUser.status, userId]);
    await kv.set(["users", "by_status", updatedUser.status, userId], userId);
  }

  return new Response(JSON.stringify(updatedUser), {
    headers: { "Content-Type": "application/json" },
  });
}

